module RefModule(
    input                       clk,

    input       [widthad-1:0]   wraddress,
    input                       wren,
    input       [width-1:0]     data,

    input       [widthad-1:0]   rdaddress,
    output reg  [width-1:0]     q
);parameter width     = 1;
parameter widthad   = 1;

reg [width-1:0] unused_mem [(2**widthad)-1:0];

always @(posedge clk) begin
    if(wren) unused_mem[wraddress] <= data;

    q <= unused_mem[rdaddress];
end

endmodule
